const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const SECRET = $env.N8N_WEBHOOK_SECRET || $env.ELEVENLABS_WEBHOOK_SECRET || '';
const TOLERANCE_SEC = 30 * 60;

const item = $input.first();
const headers = item.json.headers || {};
const sigHeader = headers['elevenlabs-signature'] || headers['ElevenLabs-Signature'] || '';
const rawBody = item.json.rawBody || JSON.stringify(item.json.body || item.json);

let verified = true;
if (SECRET) {
  const parts = sigHeader.split(',').reduce((acc, p) => { const [k, v] = p.split('='); acc[k] = v; return acc; }, {});
  const t = parts.t ? parseInt(parts.t, 10) : NaN;
  const v0 = parts.v0 || '';
  const now = Math.floor(Date.now() / 1000);
  if (!t || !v0 || Math.abs(now - t) > TOLERANCE_SEC) verified = false;
  else {
    const expected = crypto.createHmac('sha256', SECRET).update(`${t}.${rawBody}`).digest('hex');
    if (expected.length !== v0.length || !crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v0))) verified = false;
  }
}

const payload = typeof item.json.body === 'string' ? JSON.parse(item.json.body) : (item.json.body || item.json);
const today = new Date().toISOString().slice(0, 10);
const dir = path.join(process.cwd(), 'logs', 'elevenlabs', 'monitoring');
fs.mkdirSync(dir, {recursive: true});
const file = path.join(dir, `monitoring-${today}.ndjson`);
fs.appendFileSync(file, JSON.stringify({verified, received_at: new Date().toISOString(), payload}) + '\n');

return [{json: {ok: true, verified, sink: file}}];
